mapper.select:
SELECT a.*, c.city_name, c.province
FROM air_quality_data a
LEFT JOIN city c ON a.city_id = c.id

    AND a.city_id = #{cityId}

        AND c.city_name LIKE CONCAT('%', #{cityName}, '%')


        AND a.quality_level = #{qualityLevel}


        AND a.monitor_time >= #{startTime}


        AND a.monitor_time <= #{endTime}


ORDER BY a.monitor_time DESC

mapper.update:
UPDATE air_quality_data
aqi = #{aqi}, quality_level = #{qualityLevel}, primary_pollutant = #{primaryPollutant}, pm25 = #{pm25}, pm10 = #{pm10}, so2 = #{so2}, no2 = #{no2}, co = #{co}, o3 = #{o3}, temperature = #{temperature}, humidity = #{humidity}, wind_speed = #{windSpeed}, wind_direction = #{windDirection}, monitor_time = #{monitorTime},
WHERE id = #{id}
